package irvine.oeis.a086;

import java.util.HashSet;

import irvine.math.z.Z;
import irvine.oeis.a084.A084687;

/**
 * A086083 Primitive members of A084687. That is, members which cannot be generated by inserting digits into previous members in recognized patterns.
 * @author Sean A. Irvine
 */
public class A086083 extends A084687 {

  private final HashSet<Z> mA = new HashSet<>();

  @Override
  public Z next() {
    while (true) {
      final Z t = super.next();
      final String s = t.toString();
      boolean ok = true;
      for (int k = 0; k < s.length(); ++k) {
        if (mA.contains(new Z(s.substring(0, k) + s.substring(k + 1)))) {
          ok = false;
          break;
        }
      }
      mA.add(t);
      if (ok) {
        return t;
      }
    }
  }
}
